shapes.frame_eqs_str:
i=instance;     ni=num_inst;    z=ni+gmegabuf(i);

a=5*z;   a2=a;
g=a;     g2=g;

my_x = -.5 + (i%ni)/ni;
my_y = -.5 +  (i%sqrt(ni))/sqrt(ni);
my_z = -.2*z;

/////// rotations

d = 1.3; 
zoom = 1;

w1 = .2*time;
w2 = 0;
w3 = 1.;

x1 = cos(w1)*my_x + sin(w1)*my_y;
y1 = -sin(w1)*my_x + cos(w1)*my_y;
z1 = my_z;

x2 = cos(w2)*x1 + sin(w2)*z1;
z2 = -sin(w2)*x1 + cos(w2)*z1;
y2 = y1;

y3 = cos(w3)*y2 + sin(w3)*z2;
z3 = -sin(w3)*y2 + cos(w3)*z2;
x3 = x2;

l = sqrt(x3*x3 + y3*y3);
w = atan2(x3,y3);
d = sqrt(x3*x3 + y3*y3 + (z3+d)*(z3+d));
p = tan(asin(1) + atan2(d+z3,l));

my_x = zoom*sin(w)*p;
my_y = zoom*cos(w)*p;

x = .5 + my_x/q1;
y = .5 + my_y;

////////

rad=rad*zoom/d;
